const hotspotContent: Record<Locale, Record<HotspotId, HotspotContent>> = {
  nl: {
    dbh: { name: "Doggy Beach House", description: "<strong>Doggy Beach House – paradijs voor honden en hun mensen!</strong><br><br>Doggy Beach House is niet zomaar een winkel — het is een echte must-visit voor iedere hondenliefhebber in Zandvoort. Op een paar stappen van het strand vind je deze unieke plek vol kwispelende staarten, lekkere treats en good vibes.<br><br>Binnen vind je leuke én praktische spullen voor je hond: speelgoed, snacks, accessoires, cadeaus en reisgear. Op zoek naar iets speciaals? Doggy Beach House heeft ook exclusieve items die je niet overal vindt — perfect als vakantieherinnering of als cadeau.<br><br><strong>Maar het echte hoogtepunt? De Dog Bar!</strong><br><br>Bij deze one-of-a-kind dog-friendly bar is jouw hond de VIP. Honden kunnen op de bar springen (ja, echt!) en hun eigen Licky samenstellen — een hondensnack met favoriete toppings zoals rund-, lam- of groentesprinkles.<br><br>Er zijn ook koude Ice Pups, ijs en een menu vol snacks.<br><br>Wil je extra uitpakken? Check de Frikandellenmuur – een klassieke Nederlandse snackmuur, nu voor honden! Of probeer dog-friendly croissants, taco’s, burgers en meer van de Doggy Snackbar.<br><br><strong>Openingstijden:</strong><br>Maandag – zondag: 11:00 – 17:00<br>(Openingstijden kunnen variëren door weer of seizoen)<br><br>Doggy Beach House is de perfecte start van een kwispel-waardige dag in Zandvoort. Kom langs, verwen je hond en maak wat pootastische herinneringen!", photo: "https://static.wixstatic.com/media/cbdc4a_24a40e785f524c9bb87557246958d7b9~mv2.png", mapsUrl: "https://www.google.com/maps/place/Doggy+Beach+House/@52.3721086,4.5255626,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5ed505672f0ed:0x3e120ab93212091!8m2!3d52.3721086!4d4.5281375!16s%2Fg%2F11l2hvybv5?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.doggybeachhouse.com/" },
    losloop1: { name: "Strand Zandvoort", description: "<strong>Wat kun je verwachten</strong><br><br>Het strand van Zandvoort is heerlijk voor honden, maar er gelden strikte seizoensregels. In de zomer (1 mei t/m 1 oktober) zijn honden <strong>niet</strong> toegestaan op het hoofdstrand van Zandvoort tussen 09:00 en 19:00. Dit wordt streng gehandhaafd — boetes zijn mogelijk als je in deze tijden met je hond op het strand bent.<br><br>Een uitzondering is het losloopgebied ten noorden van strandafgang Parnassia, waar honden het hele jaar door los mogen — ook in de zomer.<br><br><strong>Losloopgebied (zomer &amp; winter):</strong><br>• Ten noorden van strandafgang Parnassia (richting Kattendel)<br>• Groot, rustig strandgebied<br>• Honden mogen hier altijd los<br><br><strong>Parkeren</strong><br>Parnassia parkeerplaats – direct bij het losloopgebied<br>Let op: dit gebied is ongeveer 15 minuten rijden of 1,5 uur lopen vanaf Doggy Beach House<br><br><strong>Regels &amp; tips</strong><br>• 1 mei – 1 oktober: honden niet toegestaan op Zandvoort strand tussen 09:00 en 19:00<br>• Boetes kunnen gelden<br>• 1 oktober – 1 mei: honden mogen op het hele strand los<br>• Ruim altijd poep op<br>• Water is soms beschikbaar bij strandtenten — neem voor de zekerheid zelf water mee<br><br><strong>Goed om te weten</strong><br>Het Parnassia-gebied is perfect voor lange wandelingen en losloop-plezier. Het is rustig, natuurlijk en ideaal op warme dagen.<br>Ga vroeg of laat om heet zand te vermijden en geniet van de stilte.", photo: "https://static.wixstatic.com/media/cbdc4a_8da25d76a953423abf1bc02e7ea83f0b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Zandvoort+Beach/@52.3702647,4.5289936,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec726738b42b:0xc781ffb0209b27cc!8m2!3d52.369673!4d4.520576!16s%2Fg%2F11g7nw3c_c?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop2: { name: "Duinpieperpad", description: "<p><strong>Wat kun je verwachten</strong><br><br>Het Duinpieperpad is een rustige wandelroute die start net aan de overkant van het spoor bij het Visscherspad. Gebruik het kleine tunneltje om het spoor te passeren en neem direct het pad rechts — daar begint het Duinpieperpad. De route slingert noordwaarts door stille duinen, met zowel verharde als onverharde paden.</p><p>Dit gebied is ideaal voor honden die van afwisseling houden. Aan het noordelijke einde kun je de Keesomstraat oversteken naar een klein groen gebied tussen Doctor Jacobus P. Thijsseweg en Lorentzstraat. Dit verborgen stukje is een mix van open gras en kleine duinpartijen — perfect voor een korte pauze of een laatste losloopmoment.</p><p><strong>Losloopgebied (seizoensgebonden):</strong><br>• Tussen de veeroosters: honden moeten aangelijnd<br>• Buiten die zone: honden mogen loslopen<br>• In veel delen mogen honden ook naast het verharde pad verkennen</p><p><strong>Regels &amp; tips</strong><br>• Let op borden die de aanlijnzone aangeven tussen de veeroosters<br>• Houd je hond onder controle wanneer hij losloopt<br>• Ruim altijd poep op<br>• Geen waterstations — neem zelf water mee</p><p><strong>Goed om te weten</strong><br>Het Duinpieperpad is rustiger dan strandgebieden en perfect voor een stille, natuurrijke wandeling. Het extra gebied voorbij de Keesomstraat is klein maar fijn — een leuke bonus als je nog niet naar huis wilt. Let op fietsers op de hoofdroute.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_019a0dc105f8456bbc1961b1048f3079~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Duinpieperpad,+2042+XT+Zandvoort/@52.3783107,4.5548323,567m/data=!3m2!1e3!4b1!4m15!1m8!3m7!1s0x47c5ec2843b44b05:0xe666558139c98393!2sDuinpieperpad!3b1!8m2!3d52.3893292!4d4.554374!16s%2Fg%2F1tg9grjw!3m5!1s0x47c5eea23b73150b:0x24ad1dac42ced62c!8m2!3d52.3783108!4d4.5597032!16s%2Fg%2F11g64skdnd?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop3: { name: "Visscherspad", description: "<strong>Wat kun je verwachten</strong><br><br>Visscherspad is een rustige loslooproute in de duinen tussen Zandvoort en de Amsterdamse Waterleidingduinen. Een natuurlijke, stille plek waar honden vrij kunnen ontdekken. Je loopt vooral over zandpaden met grasstukken en open duinlandschap — perfect voor relaxed rondstruinen en snuffelavonturen.<br><br><strong>Losloopgebied (zomer &amp; winter):</strong><br>• Loslopen het hele jaar toegestaan<br>• Honden mogen binnen het raster ook van het pad af en verkennen<br>• Breed, open duinterrein met vaak minder bezoekers dan strandpaden<br><br><strong>Toegang</strong><br>• Vanaf station Zandvoort: loop door de wijk Tollenstraat. Net voor Cafetaria Giomara steek je het spoor over en ga je direct links het Visscherspad op.<br>• Vanaf de gratis parkeerplaats bij Kraantje Lek: volg de borden richting Visscherspad.<br><br><strong>Parkeren</strong><br>• Gratis parkeren bij Kraantje Lek<br><br><strong>Regels &amp; tips</strong><br>• Honden mogen altijd los<br>• Houd je hond in zicht en onder controle<br>• Ruim altijd poep op<br>• Geen waterpunten — neem zelf water mee<br><br><strong>Goed om te weten</strong><br>Doordat honden binnen het raster ook buiten het pad mogen, is dit ideaal voor honden die graag vrij rennen. Let in de zomer op teken en vergeet drinkwater niet.", photo: "https://static.wixstatic.com/media/cbdc4a_75e811aeba764c9eac2c509b9d4d4751~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Visscherspad/@52.3727596,4.5584291,1772m/data=!3m1!1e3!4m15!1m8!3m7!1s0x47c5eea828bec6b3:0x479885aa13f1d3f4!2sKennemerweg,+Zandvoort!3b1!8m2!3d52.3678274!4d4.5507546!16s%2Fg%2F1tf424md!3m5!1s0x47c5eea2ba934f1d:0x82fc946d7c47aadc!8m2!3d52.3779082!4d4.5654464!16s%2Fg%2F1q5bmffg9?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak#:~:text=Honden%20zijn%20toegestaan%20op%3A,Visscherspad%3A%20los" },
    losloop4: { name: "Blinkertweg", description: "<p><strong>Wat kun je verwachten</strong><br><br>Blinkertweg is een rustig loslooppad dat grenst aan het Visscherspad, ideaal om er een langere rondwandeling van te maken. De route loopt door stille duinen met zandpaden en grasrijke stukken. Het is minder druk dan het strand en geeft honden de ruimte om ontspannen te struinen.</p><p><strong>Losloopgebied (zomer &amp; winter):</strong><br>• Honden mogen het hele jaar door los<br>• Honden mogen binnen het raster ook naast het pad verkennen<br>• Ideaal voor rustige wandelingen en natuurliefhebbers</p><p><strong>Combineer je wandeling</strong><br>Je kunt Blinkertweg eenvoudig combineren met het Visscherspad voor een mooie ronde.<br>• Terug naar station Zandvoort via het Visscherspad<br>• Of volg de route terug langs het voormalige tramtracé voor andere uitzichten</p><p><strong>Regels &amp; tips</strong><br>• Loslopen is toegestaan binnen het raster<br>• Houd je hond in zicht en onder controle<br>• Ruim poep op<br>• Geen waterpunten — neem zelf water mee</p><p><strong>Goed om te weten</strong><br>Rustig gebied met prachtige duinuitzichten. Een fijn alternatief voor honden die liever niet in de drukte lopen. Combineer met het Visscherspad voor een gevarieerde wandeling.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_6d852f6cc2bd4a96bf33eacac4a3149a~mv2.png", mapsUrl: "https://www.google.com/maps/place/Blinkertweg,+Zandvoort/@52.3712682,4.5114367,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5eebb19051607:0x29d614d21c43f696!8m2!3d52.3722973!4d4.56655!16s%2Fg%2F1thvrwys?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop5: { name: "Losloopgebied Zuid", description: "<p><strong>Wat kun je verwachten</strong><br>Losloopgebied Zuid is een ruim losloopgebied in de zuidelijke duinen van Zandvoort. Het landschap is afwisselend: zandpaden, lage duinheuvels, grasvlaktes en stukken bos.</p><p><strong>Parkeren</strong><br><em>Parkeerplaats De Zuid</em> – grote parkeerplaats in de buurt.<br><em>Kostverlorenstraat</em> – dichterbij, straatparkeren.</p><p><strong>Regels &amp; tips</strong><br>• Loslopen is het hele jaar toegestaan.<br>• Ruim poep op.<br>• Geen watervoorzieningen — neem zelf water mee.</p><p><strong>Goed om te weten</strong><br>Rustiger dan het strand. Zandpaden kunnen warm worden — ga ’s ochtends of ’s avonds.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_7c82486198114636b1273246746ab9d4~mv2.png", mapsUrl: "https://www.google.com/maps/place/Duinlandschap+Zandvoort/@52.3662546,4.5220912,949m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec0e954e6713:0x4c17eaf8f326b554!8m2!3d52.3665289!4d4.5320626!16s%2Fg%2F11dyxklqkt?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop6: { name: "Het Vliegenbos", description: "<strong>Wat kun je verwachten</strong><br><br>Het Vliegenbos is een ruim stadsbos in Amsterdam-Noord, perfect voor losloopavonturen. Het is één van de oudste stadsbossen van Nederland en heeft brede bospaden, open grasvelden en schaduwrijke stukken. In de aangewezen losloopzones kunnen honden vrij rennen, snuffelen en ontdekken.<br><br><strong>Losloopgebied (zomer &amp; winter):</strong><br>• Gemarkeerde zones door het park (duidelijk aangegeven)<br>• Bospaden, weides en open velden<br>• Loslopen het hele jaar toegestaan in deze zones<br><br><strong>Parkeren</strong><br>• Meeuwenlaan – gratis straatparkeren (kan druk zijn)<br>• Van der Pekbuurt – betaald parkeren in de buurt<br><br><strong>Regels &amp; tips</strong><br>• Alleen los in de gemarkeerde zones<br>• Houd je hond onder controle<br>• Ruim poep op<br>• Wees respectvol richting natuur en andere bezoekers<br><br><strong>Goed om te weten</strong><br>Het bos is koel en schaduwrijk — ideaal op warme dagen. Na regen kan het modderig zijn, neem een handdoek mee. Het is een lokale favoriet, dus je ontmoet vaak andere honden en baasjes.", photo: "https://static.wixstatic.com/media/cbdc4a_365dafb788b24b31b113ec180920246f~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vliegenbos/@52.3897912,4.930134,566m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c608fdcb267bf5:0x5ce7872a95a230f6!8m2!3d52.3897912!4d4.9327089!16s%2Fg%2F120q6_kd?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vliegenbos/" },
    losloop7: { name: "Rembrandtpark", description: "<strong>Wat kun je verwachten</strong><br><br>Rembrandtpark is één van de grotere en rustigere stadsparken van Amsterdam, geliefd bij hondenbezitters. Je vindt er brede paden, open grasvelden, waterpartijen en schaduw — ideaal voor een ontspannen wandeling of speelmoment.<br><br><strong>Losloopgebieden (seizoensgebonden):</strong><br>• Oostzijde: het hele jaar loslopen<br>• Westzijde:<br>– 1 november t/m 30 april: loslopen toegestaan<br>– 1 mei t/m 31 oktober: honden moeten aangelijnd<br>• Borden in het park geven de regels duidelijk aan<br><br><strong>Parkeren</strong><br>• Betaald parkeren in de buurt (bijv. Postjesweg, Orteliuskade)<br>• Openbaar vervoer: haltes Postjesweg of Jan van Galenstraat<br><br><strong>Regels &amp; tips</strong><br>• Volg de seizoensregels voor aanlijnen<br>• Ruim altijd poep op<br>• Houd je hond goed onder appèl in losloopzones<br>• Respecteer wildlife en andere bezoekers<br><br><strong>Goed om te weten</strong><br>Ruim en schaduwrijk — fijn op warme dagen. Neem zelf water mee. Rustiger dan het Vondelpark en ideaal voor honden die ruimte nodig hebben.", photo: "https://static.wixstatic.com/media/cbdc4a_66c1aceee83f413a8341257dcaf2ca4d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Rembrandtpark/@52.3647222,4.8435362,1134m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5e2141a48edf9:0x3e5e944517b46ecb!8m2!3d52.3647222!4d4.8461111!16s%2Fg%2F12q4zkc_g?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/rembrandtpark/" },
    losloop8: { name: "Vondelpark", description: "<strong>Wat kun je verwachten</strong><br><br>Het Vondelpark is het bekendste park van Amsterdam — en ook geliefd bij hondenbezitters. Het is ruim, groen en levendig. In veel delen mogen honden loslopen, waardoor het een fijne plek is om samen te wandelen, spelen en relaxen. Van open grasvelden tot schaduwrijke paden en vijvers: er is voor iedere hond wat.<br><br><strong>Losloopgebied (zomer &amp; winter):</strong><br>• In het grootste deel mogen honden los<br>• Sommige zones (zoals speeltuinen of cafés) vragen om aanlijnen — let op borden<br>• Veel open ruimte en wandelpaden<br><br><strong>Parkeren</strong><br>• Betaald straatparkeren bij ingangen (bijv. Van Baerlestraat of Amstelveenseweg)<br>• Dichtstbijzijnde tramhaltes: Vondelpark, Van Baerlestraat of Overtoom<br><br><strong>Regels &amp; tips</strong><br>• Houd je hond onder controle<br>• Ruim poep op<br>• Respecteer aanlijnzones en speelplaatsen<br>• Laat honden niet in vijvers met wildlife<br><br><strong>Goed om te weten</strong><br>Het park kan druk zijn, vooral op zonnige weekenden — maar er is bijna altijd wel plek. Je ziet locals joggen, picknicken en relaxen met hun hond. Rondom het park zijn ook hondvriendelijke cafés voor een pauze.", photo: "https://static.wixstatic.com/media/cbdc4a_47cb67b043f84ba5aa798d051fa4c06b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vondelpark/@52.354296,4.8935038,567m/data=!3m1!1e3!4m6!3m5!1s0x47c609e2c5b47ccf:0x6cd478550520ca35!8m2!3d52.3579946!4d4.8686484!16zL20vMDkwMHln?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vondelpark/" },
    losloop9: { name: "Sarphatipark", description: "<strong>Wat kun je verwachten</strong><br><br>Sarphatipark is een klein, charmant park in het hart van De Pijp (Amsterdam). In het grootste deel geldt aanlijnplicht, maar er is een aangewezen losloopzone waar honden kunnen rennen, spelen en socializen. Het is een populaire plek bij locals en ideaal voor een korte pauze tijdens je stadswandeling.<br><br><strong>Losloopgebied (zomer &amp; winter):</strong><br>• Duidelijk gemarkeerde zone in de zuidwesthoek van het park<br>• Grasveld met bomen en bankjes<br>• Loslopen het hele jaar toegestaan in deze zone<br><br><strong>Parkeren</strong><br>• Betaald parkeren in De Pijp (beperkt)<br>• Dichtstbijzijnde metro: De Pijp (Noord/Zuidlijn, M52)<br><br><strong>Regels &amp; tips</strong><br>• Alleen los in de aangewezen zone<br>• Honden moeten sociaal zijn en onder controle blijven<br>• Ruim altijd poep op<br>• In de rest van het park: aanlijnen<br><br><strong>Goed om te weten</strong><br>De losloopzone is niet groot maar wel gezellig. In de buurt zitten hondvriendelijke cafés. Ga vroeg voor meer rust, of later op de dag om andere honden te ontmoeten.", photo: "https://static.wixstatic.com/media/cbdc4a_c77384a0fc74438e93c9bc3ca86ff18d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Sarphatipark/@52.354296,4.8935038,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c6098da33cfccb:0x3583a0324d052750!8m2!3d52.354296!4d4.8960787!16s%2Fm%2F04f3t10?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/sarphatipark/" },
  },
  de: {
    dbh: { name: "Doggy Beach House", description: "<strong>Doggy Beach House – ein Paradies für Hunde und ihre Menschen!</strong><br><br>Doggy Beach House ist nicht nur ein Shop — es ist ein Must-Visit für alle Hundeliebhaber in Zandvoort. Nur ein paar Schritte vom Strand entfernt findest du einen einzigartigen Ort voller wedelnder Schwänze, leckerer Treats und guter Stimmung.<br><br>Drinnen gibt es Spaßiges und Praktisches für deinen Hund: Spielzeug, Snacks, Accessoires, Geschenke und Reise-Equipment. Du suchst etwas Besonderes? Doggy Beach House hat auch exklusive Artikel, die du nicht überall findest — perfekt als Urlaubs-Andenken oder Geschenk.<br><br><strong>Das absolute Highlight? Die Dog Bar!</strong><br><br>An dieser einzigartigen dog-friendly Bar ist dein Hund der VIP. Hunde dürfen auf die Bar springen (ja, wirklich!) und ihren eigenen Licky zusammenstellen — ein Hundetreat mit Lieblings-Toppings wie Rind-, Lamm- oder Gemüse-Sprinkles.<br><br>Außerdem gibt’s kalte Ice Pups, Eis und eine Snackkarte voller Leckereien.<br><br>Lust auf etwas Besonderes? Schau dir die Frikandellenmuur an – eine klassische niederländische Snackwand, jetzt für Hunde! Oder probier dog-friendly Croissants, Tacos, Burger und mehr aus der Doggy Snackbar.<br><br><strong>Öffnungszeiten:</strong><br>Montag – Sonntag: 11:00 – 17:00<br>(Öffnungszeiten können je nach Wetter oder Saison variieren)<br><br>Doggy Beach House ist der perfekte Start in einen schwanzwedel-würdigen Tag in Zandvoort. Komm vorbei, verwöhn deinen Hund und sammle pfotenstarke Erinnerungen!", photo: "https://static.wixstatic.com/media/cbdc4a_24a40e785f524c9bb87557246958d7b9~mv2.png", mapsUrl: "https://www.google.com/maps/place/Doggy+Beach+House/@52.3721086,4.5255626,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5ed505672f0ed:0x3e120ab93212091!8m2!3d52.3721086!4d4.5281375!16s%2Fg%2F11l2hvybv5?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.doggybeachhouse.com/" },
    losloop1: { name: "Strand Zandvoort", description: "<strong>Was dich erwartet</strong><br><br>Der Strand von Zandvoort ist toll für Hunde — allerdings gelten strenge saisonale Regeln. Im Sommer (1. Mai bis 1. Oktober) sind Hunde am Hauptstrand zwischen 09:00 und 19:00 <strong>nicht</strong> erlaubt. Das wird streng kontrolliert — Bußgelder sind möglich, wenn du in dieser Zeit mit Hund am Strand bist.<br><br>Eine Ausnahme ist die Freilaufzone nördlich des Strandaufgangs Parnassia, dort dürfen Hunde das ganze Jahr über ohne Leine laufen — auch im Sommer.<br><br><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• Nördlich des Strandaufgangs Parnassia (Richtung Kattendel)<br>• Großer, ruhiger Strandabschnitt<br>• Freilauf jederzeit erlaubt<br><br><strong>Parken</strong><br>Parnassia-Parkplatz – direkter Zugang zur Freilaufzone<br>Hinweis: ca. 15 Minuten mit dem Auto oder 1,5 Stunden zu Fuß von Doggy Beach House<br><br><strong>Regeln &amp; Hinweise</strong><br>• 1. Mai – 1. Oktober: Hunde am Zandvoort-Strand zwischen 09:00 und 19:00 nicht erlaubt<br>• Bußgelder möglich<br>• 1. Oktober – 1. Mai: Hunde dürfen am gesamten Strand frei laufen<br>• Hinterlassenschaften immer entfernen<br>• Wasser gibt es manchmal bei Strandpavillons — nimm zur Sicherheit eigenes Wasser mit<br><br><strong>Gut zu wissen</strong><br>Die Parnassia-Zone ist perfekt für lange Spaziergänge und Freilauf-Spaß. Ruhig, naturbelassen und ideal an warmen Tagen.<br>Geh früh oder später am Tag, um heißen Sand zu vermeiden und die Ruhe zu genießen.", photo: "https://static.wixstatic.com/media/cbdc4a_8da25d76a953423abf1bc02e7ea83f0b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Zandvoort+Beach/@52.3702647,4.5289936,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec726738b42b:0xc781ffb0209b27cc!8m2!3d52.369673!4d4.520576!16s%2Fg%2F11g7nw3c_c?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop2: { name: "Duinpieperpad", description: "<p><strong>Was dich erwartet</strong><br><br>Der Duinpieperpad ist eine ruhige Route, die direkt gegenüber vom Visscherspad beginnt. Durch den kleinen Tunnel unter den Gleisen gehen und gleich rechts — dort startet der Duinpieperpad. Die Strecke führt nach Norden durch stille Dünenlandschaft, mit befestigten und unbefestigten Wegen.</p><p>Perfekt für Hunde, die Abwechslung mögen. Am nördlichen Ende kannst du die Keesomstraat überqueren zu einem kleinen Grünbereich zwischen Doctor Jacobus P. Thijsseweg und Lorentzstraat. Ein verstecktes Stück mit Wiese und kleinen Dünen — ideal für eine kurze Pause oder den letzten Freilauf.</p><p><strong>Freilaufzone (saisonal):</strong><br>• Zwischen den Viehrosten: Leinenpflicht<br>• Außerhalb dieser Zone: Freilauf möglich<br>• In vielen Abschnitten dürfen Hunde auch neben dem befestigten Weg laufen</p><p><strong>Regeln &amp; Hinweise</strong><br>• Auf Schilder zur Leinenzone zwischen den Viehrosten achten<br>• Hund im Freilauf unter Kontrolle halten<br>• Hinterlassenschaften entfernen<br>• Keine Wasserstellen — eigenes Wasser mitnehmen</p><p><strong>Gut zu wissen</strong><br>Weniger besucht als Strandbereiche und ideal für einen ruhigen Naturspaziergang. Der Bereich hinter der Keesomstraat ist klein, aber angenehm — ein schöner Bonus. Auf Radfahrer entlang der Hauptroute achten.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_019a0dc105f8456bbc1961b1048f3079~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Duinpieperpad,+2042+XT+Zandvoort/@52.3783107,4.5548323,567m/data=!3m2!1e3!4b1!4m15!1m8!3m7!1s0x47c5ec2843b44b05:0xe666558139c98393!2sDuinpieperpad!3b1!8m2!3d52.3893292!4d4.554374!16s%2Fg%2F1tg9grjw!3m5!1s0x47c5eea23b73150b:0x24ad1dac42ced62c!8m2!3d52.3783108!4d4.5597032!16s%2Fg%2F11g64skdnd?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop3: { name: "Visscherspad", description: "<strong>Was dich erwartet</strong><br><br>Visscherspad ist ein ruhiger Freilaufweg in den Dünen zwischen Zandvoort und den Amsterdamse Waterleidingduinen. Natur pur und meist angenehm leer — ideal zum Schnüffeln und entspannten Umherlaufen. Hauptsächlich sandige Wege mit Grasabschnitten und offenem Dünenland.<br><br><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• Ganzjährig ohne Leine erlaubt<br>• Innerhalb des Zauns (Raster) dürfen Hunde auch abseits des Weges laufen<br>• Breites, offenes Gelände, oft weniger los als an Strandwegen<br><br><strong>Zugang</strong><br>• Ab Bahnhof Zandvoort: durch das Viertel Tollenstraat laufen. Kurz vor Cafetaria Giomara die Gleise überqueren und sofort links auf das Visscherspad.<br>• Vom kostenlosen Parkplatz bei Kraantje Lek: den Schildern Richtung Visscherspad folgen.<br><br><strong>Parken</strong><br>• Kostenlos bei Kraantje Lek<br><br><strong>Regeln &amp; Hinweise</strong><br>• Freilauf jederzeit<br>• Hund in Sichtweite und unter Kontrolle halten<br>• Hinterlassenschaften entfernen<br>• Keine Wasserstellen — eigenes Wasser mitnehmen<br><br><strong>Gut zu wissen</strong><br>Da Hunde innerhalb des Zauns auch neben dem Weg laufen dürfen, ist das ideal für Hunde, die gerne frei rennen. Im Sommer auf Zecken achten und Trinkwasser mitnehmen.", photo: "https://static.wixstatic.com/media/cbdc4a_75e811aeba764c9eac2c509b9d4d4751~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Visscherspad/@52.3727596,4.5584291,1772m/data=!3m1!1e3!4m15!1m8!3m7!1s0x47c5eea828bec6b3:0x479885aa13f1d3f4!2sKennemerweg,+Zandvoort!3b1!8m2!3d52.3678274!4d4.5507546!16s%2Fg%2F1tf424md!3m5!1s0x47c5eea2ba934f1d:0x82fc946d7c47aadc!8m2!3d52.3779082!4d4.5654464!16s%2Fg%2F1q5bmffg9?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak#:~:text=Honden%20zijn%20toegestaan%20op%3A,Visscherspad%3A%20los" },
    losloop4: { name: "Blinkertweg", description: "<p><strong>Was dich erwartet</strong><br><br>Blinkertweg ist ein ruhiger Freilaufweg entlang des Visscherspad — perfekt für eine längere Runde. Die Route führt durch stille Dünen mit sandigen Wegen und grasigen Abschnitten. Weniger Trubel als am Strand und sehr entspannt für Hunde.</p><p><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• Ganzjährig ohne Leine<br>• Innerhalb des Zauns (Raster) auch neben dem Weg möglich<br>• Ideal für ruhige Spaziergänge und Naturliebhaber</p><p><strong>Route kombinieren</strong><br>Du kannst Blinkertweg leicht mit dem Visscherspad zu einer schönen Runde verbinden.<br>• Zurück Richtung Bahnhof Zandvoort über das Visscherspad<br>• Oder über die ehemalige Tramtrasse für Abwechslung</p><p><strong>Regeln &amp; Hinweise</strong><br>• Freilauf innerhalb des Rasters erlaubt<br>• Hund in Sichtweite und unter Kontrolle halten<br>• Hinterlassenschaften entfernen<br>• Keine Wasserstellen — eigenes Wasser mitnehmen</p><p><strong>Gut zu wissen</strong><br>Ruhig, mit schönen Dünenblicken. Gute Alternative, wenn dein Hund es lieber entspannt mag. Kombiniert mit dem Visscherspad besonders abwechslungsreich.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_6d852f6cc2bd4a96bf33eacac4a3149a~mv2.png", mapsUrl: "https://www.google.com/maps/place/Blinkertweg,+Zandvoort/@52.3712682,4.5114367,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5eebb19051607:0x29d614d21c43f696!8m2!3d52.3722973!4d4.56655!16s%2Fg%2F1thvrwys?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop5: { name: "Freilaufgebiet Süd", description: "<p><strong>Was dich erwartet</strong><br>Losloopgebied Zuid ist eine großzügige Freilaufzone in den südlichen Dünen von Zandvoort. Die Landschaft ist abwechslungsreich: sandige Wege, niedrige Dünenhügel, Wiesen und Waldstücke.</p><p><strong>Parken</strong><br><em>Parkeerplaats De Zuid</em> – großer Parkplatz in der Nähe.<br><em>Kostverlorenstraat</em> – näher dran, Parken an der Straße.</p><p><strong>Regeln &amp; Hinweise</strong><br>• Freilauf ganzjährig erlaubt.<br>• Hinterlassenschaften entfernen.<br>• Keine Wasserstellen — nimm eigenes Wasser mit.</p><p><strong>Gut zu wissen</strong><br>Ruhiger als der Strand. Sandwege können heiß werden — morgens oder abends ist es angenehmer.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_7c82486198114636b1273246746ab9d4~mv2.png", mapsUrl: "https://www.google.com/maps/place/Duinlandschap+Zandvoort/@52.3662546,4.5220912,949m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec0e954e6713:0x4c17eaf8f326b554!8m2!3d52.3665289!4d4.5320626!16s%2Fg%2F11dyxklqkt?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop6: { name: "Het Vliegenbos", description: "<strong>Was dich erwartet</strong><br><br>Het Vliegenbos ist ein großer Stadtwald in Amsterdam-Noord und perfekt für Freilauf-Abenteuer. Einer der ältesten Stadtwälder der Niederlande mit breiten Wegen, offenen Wiesen und schattigen Abschnitten. In den ausgewiesenen Freilaufzonen können Hunde frei laufen, schnüffeln und entdecken.<br><br><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• Markierte Zonen im Park (gut ausgeschildert)<br>• Waldwege, Wiesen und offene Felder<br>• Ganzjährig Freilauf in diesen Zonen erlaubt<br><br><strong>Parken</strong><br>• Meeuwenlaan – kostenloses Parken an der Straße (kann voll sein)<br>• Van-der-Pekbuurt – kostenpflichtig in der Nähe<br><br><strong>Regeln &amp; Hinweise</strong><br>• Nur in den markierten Bereichen ohne Leine<br>• Hund stets unter Kontrolle<br>• Hinterlassenschaften entfernen<br>• Rücksicht auf Natur und andere Besucher<br><br><strong>Gut zu wissen</strong><br>Viel Schatten — ideal an warmen Tagen. Nach Regen kann es schlammig werden; ein Handtuch ist praktisch. Beliebter Spot, oft triffst du andere Hunde und Halter.", photo: "https://static.wixstatic.com/media/cbdc4a_365dafb788b24b31b113ec180920246f~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vliegenbos/@52.3897912,4.930134,566m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c608fdcb267bf5:0x5ce7872a95a230f6!8m2!3d52.3897912!4d4.9327089!16s%2Fg%2F120q6_kd?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vliegenbos/" },
    losloop7: { name: "Rembrandtpark", description: "<strong>Was dich erwartet</strong><br><br>Der Rembrandtpark ist einer der größeren und ruhigeren Parks in Amsterdam, beliebt bei Hundebesitzern. Breite Wege, Wiesen, Wasser und Schatten — ideal für einen entspannten Spaziergang oder eine Spielpause.<br><br><strong>Freilaufbereiche (saisonal):</strong><br>• Ostseite: ganzjährig Freilauf<br>• Westseite:<br>– 1. November bis 30. April: Freilauf erlaubt<br>– 1. Mai bis 31. Oktober: Leinenpflicht<br>• Schilder im Park erklären die Regeln<br><br><strong>Parken</strong><br>• Parken an der Straße (kostenpflichtig), z.B. Postjesweg, Orteliuskade<br>• ÖPNV: Haltestellen Postjesweg oder Jan van Galenstraat<br><br><strong>Regeln &amp; Hinweise</strong><br>• Saisonregeln beachten<br>• Hinterlassenschaften entfernen<br>• In Freilaufzonen abrufbar/unter Kontrolle halten<br>• Rücksicht auf Wildtiere und Besucher<br><br><strong>Gut zu wissen</strong><br>Viel Platz und Schatten — angenehm bei Wärme. Eigenes Wasser mitnehmen. Ruhiger als der Vondelpark und gut für Hunde, die mehr Raum brauchen.", photo: "https://static.wixstatic.com/media/cbdc4a_66c1aceee83f413a8341257dcaf2ca4d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Rembrandtpark/@52.3647222,4.8435362,1134m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5e2141a48edf9:0x3e5e944517b46ecb!8m2!3d52.3647222!4d4.8461111!16s%2Fg%2F12q4zkc_g?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/rembrandtpark/" },
    losloop8: { name: "Vondelpark", description: "<strong>Was dich erwartet</strong><br><br>Der Vondelpark ist Amsterdams bekanntester Park — und ein Favorit für Hundebesitzer. Groß, grün und lebendig. In vielen Bereichen ist Freilauf erlaubt, perfekt zum Spazieren, Spielen und Entspannen. Von offenen Wiesen bis zu schattigen Wegen und Teichen ist alles dabei.<br><br><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• In den meisten Bereichen ohne Leine<br>• Einige Zonen (Spielplätze/Cafés) erfordern Leine — auf Schilder achten<br>• Viele Wege und offene Flächen<br><br><strong>Parken</strong><br>• Parken an der Straße (kostenpflichtig) nahe der Eingänge, z.B. Van Baerlestraat oder Amstelveenseweg<br>• Nächste Tramhaltestellen: Vondelpark, Van Baerlestraat oder Overtoom<br><br><strong>Regeln &amp; Hinweise</strong><br>• Hund stets unter Kontrolle<br>• Hinterlassenschaften entfernen<br>• Leinenzonen und Spielplätze respektieren<br>• Hunde aus Teichen mit Wildtieren fernhalten<br><br><strong>Gut zu wissen</strong><br>Kann sehr belebt sein, besonders an sonnigen Wochenenden — trotzdem findet man meist Platz. Viele Locals joggen, picknicken oder entspannen. Rund um den Park gibt es hundefreundliche Cafés für eine Pause.", photo: "https://static.wixstatic.com/media/cbdc4a_47cb67b043f84ba5aa798d051fa4c06b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vondelpark/@52.354296,4.8935038,567m/data=!3m1!1e3!4m6!3m5!1s0x47c609e2c5b47ccf:0x6cd478550520ca35!8m2!3d52.3579946!4d4.8686484!16zL20vMDkwMHln?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vondelpark/" },
    losloop9: { name: "Sarphatipark", description: "<strong>Was dich erwartet</strong><br><br>Der Sarphatipark ist ein kleiner, charmanter Park im Viertel De Pijp. Meist gilt Leinenpflicht, aber es gibt eine ausgewiesene Freilaufzone, in der Hunde rennen, spielen und sozialisieren können. Beliebt bei Einheimischen — ideal für eine kurze Pause beim Stadtspaziergang.<br><br><strong>Freilaufzone (Sommer &amp; Winter):</strong><br>• Markierter Bereich in der südwestlichen Ecke des Parks<br>• Wiese mit Bäumen und Bänken<br>• Ganzjährig Freilauf in diesem Bereich<br><br><strong>Parken</strong><br>• Parken an der Straße (kostenpflichtig, begrenzt)<br>• Nächste Metro: De Pijp (Noord/Zuidlijn, M52)<br><br><strong>Regeln &amp; Hinweise</strong><br>• Freilauf nur in der ausgewiesenen Zone<br>• Hund sollte sozial und kontrollierbar sein<br>• Hinterlassenschaften entfernen<br>• Im restlichen Park: Leine<br><br><strong>Gut zu wissen</strong><br>Die Freilaufzone ist nicht groß, aber gesellig. In der Umgebung gibt es hundefreundliche Cafés. Früh am Tag ist es ruhiger; später trifft man eher andere Hunde.", photo: "https://static.wixstatic.com/media/cbdc4a_c77384a0fc74438e93c9bc3ca86ff18d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Sarphatipark/@52.354296,4.8935038,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c6098da33cfccb:0x3583a0324d052750!8m2!3d52.354296!4d4.8960787!16s%2Fm%2F04f3t10?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/sarphatipark/" },
  },
  en: {
    dbh: { name: "Doggy Beach House", description: "<strong>Doggy Beach House – paradise for dogs and their humans!</strong><br><br>Doggy Beach House is not just a shop — it’s a must-visit spot for every dog lover in Zandvoort. Just a few steps from the beach, this unique store is full of wagging tails, tasty treats and good vibes.<br><br>Inside you’ll find fun and practical items for your dog: toys, snacks, accessories, gifts and travel gear. Looking for something special? Doggy Beach House has exclusive items you won’t find anywhere else — perfect for holiday memories or gifts.<br><br><strong>But the real highlight? The Dog Bar!</strong><br><br>At this one-of-a-kind dog-friendly bar, your pup is the VIP. Dogs can hop up on the bar (yes, really!) and create their own Licky – a dog treat with their favorite toppings like beef,- lamb-, or veggie sprinkles.<br><br> There are also cold Ice Pups, ice cream, and a menu full of snacks.<br><br>Feeling fancy? Check out the Frikandellenmuur – a classic Dutch snack wall, now for dogs! Or try the dog-friendly croissants, taco’s, burgers and more from the Doggy Snackbar.<br><br><strong>Opening hours:</strong><br>Monday – Sunday: 11:00 – 17:00<br>(Opening hours may vary with weather or season)<br><br>Doggy Beach House is the perfect start to a wag-worthy day in Zandvoort. Stop by, spoil your dog, and snap some pawsome memories!", photo: "https://static.wixstatic.com/media/cbdc4a_24a40e785f524c9bb87557246958d7b9~mv2.png", mapsUrl: "https://www.google.com/maps/place/Doggy+Beach+House/@52.3721086,4.5255626,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5ed505672f0ed:0x3e120ab93212091!8m2!3d52.3721086!4d4.5281375!16s%2Fg%2F11l2hvybv5?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.doggybeachhouse.com/" },
    losloop1: { name: "Zandvoort Beach", description: "<strong>What to Expect</strong><br><br>The beach in Zandvoort is a great place for dogs to enjoy the sand and sea — but there are strict seasonal rules. During summer (1 May to 1 October), dogs are <strong>not</strong> allowed on the main Zandvoort beach between 09:00 and 19:00. This rule is strictly enforced — fines may be issued if you are on the beach with your dog during these hours.<br><br>One exception is the off-leash zone north of the Parnassia beach exit, where dogs are welcome off-leash all year round, even in summer.<br><br><strong>Off-leash area (summer & winter):</strong><br>• North of Parnassia beach exit (towards Kattendel)<br>• Large, quiet beach area<br>• Dogs allowed off-leash at all times<br><br><strong>Parking</strong><br>Parnassia parking lot – direct access to the off-leash zone<br>Note: This area is about 15 minutes by car or 1.5 hours on foot from Doggy Beach House<br><br><strong>Rules & Guidelines</strong><br>• 1 May – 1 October: Dogs not allowed on Zandvoort beach between 09:00 and 19:00<br>• Fines may apply during these hours<br>• 1 October – 1 May: Dogs allowed off-leash on the entire beach<br>• Always clean up after your dog<br>• Water available at beach clubs — but bring your own<br><br><strong>Good to Know</strong><br>The Parnassia beach zone is perfect for long walks and off-leash fun.It’s quiet, natural, and ideal on warm days<br>Go early or late to avoid hot sand and enjoy the peaceful surroundings.", photo: "https://static.wixstatic.com/media/cbdc4a_8da25d76a953423abf1bc02e7ea83f0b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Zandvoort+Beach/@52.3702647,4.5289936,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec726738b42b:0xc781ffb0209b27cc!8m2!3d52.369673!4d4.520576!16s%2Fg%2F11g7nw3c_c?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop2: { name: "Duinpieperpad", description: "<p><strong>What to Expect</strong><br><br>The Duinpieperpad is a quiet walking route that starts just across the train tracks from the Visscherspad. Use the small tunnel to cross the tracks and take the path immediately to the right — this is the start of the Duinpieperpad. The route winds north through peaceful dune landscapes, with both paved and unpaved paths to choose from.</p><p>This area allows for more adventurous exploration, and it's great for dogs who enjoy variety. As you reach the northern end of the trail, you can cross the Keesomstraat into a small green zone nestled between Doctor Jacobus P. Thijsseweg and Lorentzstraat. This hidden area is a mix of open grassland and small dune patches — ideal for a short break or final stretch of off-leash fun.</p><p><strong>Off-leash area (seasonal):</strong><br>• Between the cattle grids (veeroosters): dogs must be leashed<br>• Outside of that zone: dogs may run off-leash<br>• Dogs are also allowed to explore off the paved trail in many sections</p><p><strong>Rules & Guidelines</strong><br>• Pay attention to signs marking the on-leash zone between veeroosters<br>• Keep dogs under control when off-leash<br>• Always clean up after your dog<br>• No water stations — bring your own</p><p><strong>Good to Know</strong><br>The Duinpieperpad is less visited than beach areas and perfect for a quiet, nature-filled walk. The connected area beyond Keesomstraat is small but peaceful — a nice bonus if you're not ready to head home yet. Watch out for cyclists along the main paths.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_019a0dc105f8456bbc1961b1048f3079~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Duinpieperpad,+2042+XT+Zandvoort/@52.3783107,4.5548323,567m/data=!3m2!1e3!4b1!4m15!1m8!3m7!1s0x47c5ec2843b44b05:0xe666558139c98393!2sDuinpieperpad!3b1!8m2!3d52.3893292!4d4.554374!16s%2Fg%2F1tg9grjw!3m5!1s0x47c5eea23b73150b:0x24ad1dac42ced62c!8m2!3d52.3783108!4d4.5597032!16s%2Fg%2F11g64skdnd?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop3: { name: "Visscherspad", description: "<strong>What to Expect</strong><br><br>Visscherspad is a quiet off-leash trail located in the dunes between Zandvoort and the Amsterdamse Waterleidingduinen. It offers a natural, peaceful escape where dogs can explore freely. The area is mostly sandy paths with grassy sections and open dune landscape — perfect for relaxed roaming and sniffing adventures.<br><br><strong>Off-leash area (summer & winter):</strong><br>• Off-leash allowed year-round<br>• Dogs may go off-trail and explore within the fenced dune area (inside the rasters)<br>• Wide, open dune terrain with fewer visitors than beach paths<br><br><strong>Acces</strong><br>• From Zandvoort station: Walk through the Tollenstraat neighborhood. Just before Cafetaria Giomara, cross the train tracks and immediately turn left onto Visscherspad.<br>• From the free parking lot at Kraantje Lek: Follow the signs toward Visscherspad.<br><br><strong>Parking</strong><br>• Free parking at Kraantje Lek<br><br><strong>Rules & Guidelines</strong><br>• Dogs allowed off-leash at all times<br>• Keep dogs within sight and under control<br>• Always clean up after your dog<br>• No water points — bring your own<br><br><strong>Good to Know</strong><br>Because dogs are allowed outside the path within the fenced dunes, this spot is ideal for dogs that enjoy free running. Watch out for ticks in summer and don’t forget to bring drinking water.", photo: "https://static.wixstatic.com/media/cbdc4a_75e811aeba764c9eac2c509b9d4d4751~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Visscherspad/@52.3727596,4.5584291,1772m/data=!3m1!1e3!4m15!1m8!3m7!1s0x47c5eea828bec6b3:0x479885aa13f1d3f4!2sKennemerweg,+Zandvoort!3b1!8m2!3d52.3678274!4d4.5507546!16s%2Fg%2F1tf424md!3m5!1s0x47c5eea2ba934f1d:0x82fc946d7c47aadc!8m2!3d52.3779082!4d4.5654464!16s%2Fg%2F1q5bmffg9?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak#:~:text=Honden%20zijn%20toegestaan%20op%3A,Visscherspad%3A%20los" },
    losloop4: { name: "Blinkertweg", description: "<p><strong>What to Expect</strong><br><br>Blinkertweg is a quiet off-leash path that borders the Visscherspad, making it perfect for a longer circular walk. The route runs through peaceful dunes with sandy trails and grassy areas. It’s less crowded than the beach and offers a relaxed, natural environment for dogs to roam freely.</p><p><strong>Off-leash area (summer & winter):</strong><br>• Dogs allowed off-leash year-round<br>• Dogs may go beyond the path and explore inside the fenced dune areas (within the rasters)<br>• Ideal for calm walks and nature lovers</p><p><strong>Combine your walk</strong><br>You can easily combine Blinkertweg with the Visscherspad to create a scenic round trip.<br>• Return to Zandvoort station via the Visscherspad<br>• Or follow the route back along the former tram line for a change of scenery</p><p><strong>Rules & Guidelines</strong><br>• Dogs allowed off-leash within the fenced dune areas<br>• Always keep your dog within sight and under control<br>• Clean up after your dog<br>• No water points — bring your own</p><p><strong>Good to Know</strong><br>This area is quieter than the beach and offers beautiful dune views. It’s a great alternative for dogs who prefer peaceful, natural surroundings. Combine with the Visscherspad for a varied and scenic walk.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_6d852f6cc2bd4a96bf33eacac4a3149a~mv2.png", mapsUrl: "https://www.google.com/maps/place/Blinkertweg,+Zandvoort/@52.3712682,4.5114367,4533m/data=!3m1!1e3!4m6!3m5!1s0x47c5eebb19051607:0x29d614d21c43f696!8m2!3d52.3722973!4d4.56655!16s%2Fg%2F1thvrwys?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.np-zuidkennemerland.nl/2131/zien/van-woeste-duinen-tot-duingrasland/kraansvlak" },
    losloop5: { name: "Off-Leash area Zuid", description: "<p><strong>What to Expect</strong><br>Losloopgebied Zuid is a spacious off-leash zone in the southern dunes of Zandvoort. The landscape is diverse, with sandy trails, low dune hills, grassy plains, and patches of forest.</p><p><strong>Parking</strong><br><em>Parkeerplaats De Zuid</em> – large car park nearby.<br><em>Kostverlorenstraat</em> – closer street parking.</p><p><strong>Rules & Guidelines</strong><br>• Off-leash allowed year-round.<br>• Clean up after your dog.<br>• No water facilities — bring your own.</p><p><strong>Good to Know</strong><br>Quiet compared to the beach. Sandy trails can get hot — walk in the morning/evening.</p>", photo: "https://static.wixstatic.com/media/cbdc4a_7c82486198114636b1273246746ab9d4~mv2.png", mapsUrl: "https://www.google.com/maps/place/Duinlandschap+Zandvoort/@52.3662546,4.5220912,949m/data=!3m1!1e3!4m6!3m5!1s0x47c5ec0e954e6713:0x4c17eaf8f326b554!8m2!3d52.3665289!4d4.5320626!16s%2Fg%2F11dyxklqkt?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://zandvoort.nl/regels-voor-hondenbezitters" },
    losloop6: { name: "Het Vliegenbos", description: "<strong>What to Expect</strong><br><br>Het Vliegenbos is a spacious urban forest in Amsterdam-Noord, perfect for off-leash adventures. It’s one of the oldest city forests in the Netherlands and features a mix of wide forest paths, open grassy fields, and shaded woodland trails. Dogs can run, sniff and explore freely in the designated off-leash zones.<br><br><strong>Off-leash area (summer & winter):</strong><br>• Marked zones throughout the park (clearly signposted)<br>• Forest paths, meadows, and open fields<br>• Dogs allowed off-leash year-round in these zones<br><br><strong>Parking</strong><br>• Meeuwenlaan – free street parking (can be busy)<br>• Van der Pekbuurt – nearby paid parking<br><br><strong>Rules & Guidelines</strong><br>• Off-leash only in marked areas<br>• Keep your dog under control at all times<br>• Clean up after your dog<br>• Be respectful of nature and other visitors<br><br><strong>Good to Know</strong><br>The forest is cool and shaded, making it great for hot days. After rain, it can get muddy — bring a towel for your dog. It’s a local favorite, so expect to meet other friendly dogs and owners.", photo: "https://static.wixstatic.com/media/cbdc4a_365dafb788b24b31b113ec180920246f~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vliegenbos/@52.3897912,4.930134,566m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c608fdcb267bf5:0x5ce7872a95a230f6!8m2!3d52.3897912!4d4.9327089!16s%2Fg%2F120q6_kd?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vliegenbos/" },
    losloop7: { name: "Rembrandtpark", description: "<strong>What to Expect</strong><br><br>Rembrandtpark is one of Amsterdam’s larger and quieter city parks, loved by local dog owners. It offers wide walking paths, grassy open fields, ponds, and shaded areas — ideal for a relaxed walk, play session, or a peaceful break with your dog.<br><br><strong>Off-leash areas (seasonal):</strong><br>• Eastern side of the park: off-leash all year round<br>• Western side of the park:<br>– 1 November to 30 April: off-leash allowed<br>– 1 May to 31 October: dogs must be leashed<br>• Signs throughout the park clearly indicate the rules<br><br><strong>Parking</strong><br>• Paid street parking nearby (e.g. Postjesweg, Orteliuskade)<br>• Closest public transport: Postjesweg of Jan van Galenstraat<br><br><strong>Rules & Guidelines</strong><br>• Follow seasonal leash rules<br>• Always clean up after your dog<br>• Keep dogs under voice control in off-leash areas<br>• Respect wildlife and other visitors<br><br><strong>Good to Know</strong><br>The park is spacious and shaded — ideal on warm days. Bring your own water for your dog. It’s quieter than Vondelpark and great for dogs who need space.", photo: "https://static.wixstatic.com/media/cbdc4a_66c1aceee83f413a8341257dcaf2ca4d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Rembrandtpark/@52.3647222,4.8435362,1134m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c5e2141a48edf9:0x3e5e944517b46ecb!8m2!3d52.3647222!4d4.8461111!16s%2Fg%2F12q4zkc_g?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/rembrandtpark/" },
    losloop8: { name: "Vondelpark", description: "<strong>What to Expect</strong><br><br>The Vondelpark is Amsterdam's most famous city park — and a favorite among dog owners. It's spacious, green, and full of life. Dogs are allowed off-leash in most parts of the park, making it a fantastic place to explore, play, and relax together. From wide open lawns to shady paths and ponds, there's something for every pup.<br><br><strong>Off-leash area (summer & winter):</strong><br>• Most of the park allows dogs off-leash<br>• Some areas (like playgrounds or cafés) require leashes — look for signs<br>• Plenty of open spaces and walking paths<br><br><strong>Parking</strong><br>• Paid street parking near entrances (e.g. Van Baerlestraat of Amstelveenseweg)<br>• Closest tram stops: Vondelpark, Van Baerlestraat, of Overtoom<br><br><strong>Rules & Guidelines</strong><br>• Dogs must be under control at all times<br>• Clean up after your dog<br>• Respect on-leash zones and playgrounds<br>• Keep dogs out of ponds with wildlife<br><br><strong>Good to Know</strong><br>The park can be busy — especially on sunny weekends — but there's always space to roam. You'll often see locals jogging, picnicking, of relaxing with their dogs. There are several dog-friendly cafés around the park for a snack of coffee break after your walk.", photo: "https://static.wixstatic.com/media/cbdc4a_47cb67b043f84ba5aa798d051fa4c06b~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Vondelpark/@52.354296,4.8935038,567m/data=!3m1!1e3!4m6!3m5!1s0x47c609e2c5b47ccf:0x6cd478550520ca35!8m2!3d52.3579946!4d4.8686484!16zL20vMDkwMHln?entry=ttu", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/vondelpark/" },
    losloop9: { name: "Sarphati Park", description: "<strong>What to Expect</strong><br><br>Sarphatipark is a small, charming city park in the heart of Amsterdam’s De Pijp neighborhood. While most of the park is on-leash, there’s a designated off-leash zone where dogs can run, play and socialize. It’s a popular spot with locals and ideal for a short break or playtime during your city walk.<br><br><strong>Off-leash area (summer & winter):</strong><br>• Clearly marked zone in the southwest corner of the park<br>• Grassy area with trees and benches<br>• Dogs allowed off-leash year-round in this section<br><br><strong>Parking</strong><br>• Paid street parking around De Pijp (can be limited)<br>• Closest metro stop: De Pijp (Noord/Zuidlijn, M52)<br><br><strong>Rules & Guidelines</strong><br>• Off-leash only in the designated zone<br>• Dogs must be well-behaved and under voice control<br>• Always clean up after your dog<br>• Keep dogs leashed in all other areas of the park<br><br><strong>Good to Know</strong><br>The off-leash area is relatively small but social. It's surrounded by a lively neighborhood with dog-friendly cafés nearby. Visit early in the day for a quieter experience or after work to meet local dog owners.", photo: "https://static.wixstatic.com/media/cbdc4a_c77384a0fc74438e93c9bc3ca86ff18d~mv2.jpg", mapsUrl: "https://www.google.com/maps/place/Sarphatipark/@52.354296,4.8935038,567m/data=!3m2!1e3!4b1!4m6!3m5!1s0x47c6098da33cfccb:0x3583a0324d052750!8m2!3d52.354296!4d4.8960787!16s%2Fm%2F04f3t10?entry=ttu&g_ep=EgoyMDI1MDcyMy4wIKXMDSoASAFQAw%3D%3D", websiteUrl: "https://www.amsterdam.nl/leefomgeving/parken-recreatiegebieden/sarphatipark/" },
  },
};

export function getHotspotContent(locale: Locale, id: HotspotId): HotspotContent {
  return hotspotContent[locale][id] ?? hotspotContent.nl[id];
}
